def gen(rng, size):
    n = size
    manager = [-1] * n
    for i in range(1, n):
        manager[i] = rng.randint(0, i - 1)
    informTime = [0] * n
    for i in range(n):
        if any(manager[j] == i for j in range(n)):
            informTime[i] = rng.randint(0, 100)
    return [n, 0, manager, informTime]

