class Solution:
    def numOfMinutes(self, n: int, headID: int, manager, informTime) -> int:
        from collections import defaultdict
        children = defaultdict(list)
        for emp, mgr in enumerate(manager):
            if mgr != -1:
                children[mgr].append(emp)
        def dfs(node):
            if not children[node]:
                return 0
            return informTime[node] + max(dfs(c) for c in children[node])
        import sys
        sys.setrecursionlimit(200000)
        return dfs(headID)

